fn shooting_system(world: &mut World, dt: f32) {
// 1. COLLECTION: Storage borrowed immutably here
let mut spawn_requests = Vec::new();
{
let spawners = world.query::<&mut Spawner>();
let positions = world.query::<&Position>();
for (ent, s, p) in spawners.iter() {
if s.tick(dt) {
spawn_requests.push((*p, s.bullet_speed));
}
}
} // <- Immutables dropped here

pre.code:
// 2. RECORDING: Command buffer records intent
let mut commands = world.get_command_buffer();
for (pos, speed) in spawn_requests {
    let b = commands.spawn();
    commands.insert(b, pos);
    commands.insert(b, Velocity::from_speed(speed));
    commands.insert(b, BulletMarker);
}
